import React, { useState } from 'react';
import './EditPurchase.css';

const EditPurchase = ({ purchase, handleUpdate, vendors, locations }) => {
  const [updatedPurchase, setUpdatedPurchase] = useState({
    ...purchase,
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUpdatedPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleUpdate(updatedPurchase);
  };

  const handleLocationChange = (e) => {
    const { value } = e.target;
    const selectedLocation = locations.find((location) => location.id === value);
    setUpdatedPurchase((prevPurchase) => ({
      ...prevPurchase,
      location: value,
      locationName: selectedLocation ? selectedLocation.locationname : '',
    }));
  };

  const handleVendorChange = (e) => {
    const { value } = e.target;
    const selectedVendor = vendors.find((vendor) => vendor.vendorid === value);
    setUpdatedPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendor: value,
      vendorName: selectedVendor ? selectedVendor.name : '',
    }));
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label>Location:</label>
        <select
          name="location"
          value={updatedPurchase.location}
          onChange={handleLocationChange}
          required
        >
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input
          type="text"
          name="materialid"
          value={updatedPurchase.materialid}
          onChange={handleChange}
          required
        />
      </div>
      <div>
        <label>Material Name:</label>
        <input
          type="text"
          name="name"
          value={updatedPurchase.name}
          onChange={handleChange}
          required
        />
      </div>
      <div>
        <label>Quantity:</label>
        <input
          type="text"
          name="quantity"
          value={updatedPurchase.quantity}
          onChange={handleChange}
          required
        />
      </div>
      <div>
        <label>Price:</label>
        <input
          type="text"
          name="price"
          value={updatedPurchase.price}
          onChange={handleChange}
          required
        />
      </div>
      <div>
        <label>Vendor:</label>
        <select
          name="vendor"
          value={updatedPurchase.vendor}
          onChange={handleVendorChange}
          required
        >
          <option value="">Select a vendor</option>
          {vendors.map((vendor) => (
            <option key={vendor.vendorid} value={vendor.vendorid}>
              {vendor.name}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Date:</label>
        <input
          type="text"
          name="date"
          value={updatedPurchase.date}
          onChange={handleChange}
          required
        />
      </div>
      <button type="submit">Save</button>
    </form>
  );
};

export default EditPurchase;
